package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.logout.SecurityContextLogoutHandler;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;

@Controller
public class LogoutController {

    private static final Logger logger = LoggerFactory.getLogger(LogoutController.class);

    @Value("${sso.logout.default-redirect-url:/login?logout}")
    private String defaultRedirectUrl;

    @Value("${sso.logout.allowed-redirect-domains:}")
    private List<String> allowedRedirectDomains;

    @GetMapping("/logout")
    public void logout(HttpServletRequest request,
                       HttpServletResponse response,
                       @RequestParam(name = "next", required = false) String next) throws IOException {

        // Perform logout - invalidate session and clear security context
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication != null) {
            new SecurityContextLogoutHandler().logout(request, response, authentication);
        }

        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        SecurityContextHolder.clearContext();

        // Validate and sanitize the redirect URL to prevent Open Redirect attacks
        String safeRedirectUrl = validateRedirectUrl(next);

        logger.info("User logged out. Redirecting to: {}", safeRedirectUrl);

        response.sendRedirect(safeRedirectUrl);
    }

    /**
     * Validates the redirect URL against an allowlist of domains
     * to prevent Open Redirect vulnerabilities.
     *
     * SECURITY NOTE: Never redirect to an unvalidated user-supplied URL.
     * The original requirement of using request.getParameter("next") directly
     * is an Open Redirect vulnerability (CWE-601).
     */
    private String validateRedirectUrl(String redirectUrl) {
        if (redirectUrl == null || redirectUrl.isBlank()) {
            return defaultRedirectUrl;
        }

        // Block protocol-relative URLs (e.g., //evil.com)
        if (redirectUrl.startsWith("//")) {
            logger.warn("Blocked protocol-relative redirect attempt: {}", redirectUrl);
            return defaultRedirectUrl;
        }

        // Allow relative URLs that start with / (same-origin)
        if (redirectUrl.startsWith("/") && !redirectUrl.startsWith("//")) {
            // Prevent header injection via CRLF
            if (redirectUrl.contains("\r") || redirectUrl.contains("\n")) {
                logger.warn("Blocked CRLF injection attempt in redirect URL");
                return defaultRedirectUrl;
            }
            return redirectUrl;
        }

        // For absolute URLs, validate against the allowed domains list
        try {
            URI uri = new URI(redirectUrl);
            String scheme = uri.getScheme();
            String host = uri.getHost();

            if (host == null || scheme == null) {
                logger.warn("Blocked redirect with missing host or scheme: {}", redirectUrl);
                return defaultRedirectUrl;
            }

            // Only allow http and https schemes
            if (!scheme.equalsIgnoreCase("http") && !scheme.equalsIgnoreCase("https")) {
                logger.warn("Blocked redirect with disallowed scheme: {}", scheme);
                return defaultRedirectUrl;
            }

            // Check against allowed domains
            for (String allowedDomain : allowedRedirectDomains) {
                if (host.equalsIgnoreCase(allowedDomain) ||
                        host.endsWith("." + allowedDomain)) {
                    return redirectUrl;
                }
            }

            logger.warn("Blocked redirect to untrusted domain: {}", host);
            return defaultRedirectUrl;

        } catch (URISyntaxException e) {
            logger.warn("Blocked redirect with malformed URL: {}", redirectUrl);
            return defaultRedirectUrl;
        }
    }
}